module top_module(
	input wire clk, reset,
	input wire level,
	output reg tick
);localparam [1:0] zero = 2'b00,
						edg = 2'b01,
						one = 2'b10;


reg [1:0] alt_state_reg, state_next;


always @(posedge clk, posedge reset)
if (reset)
	alt_state_reg <= zero;
else
	alt_state_reg <= state_next;



always @(alt_state_reg, level)
begin
	state_next = alt_state_reg; 
	tick = 1'b0; 
	case (alt_state_reg)
		zero:
			if (level)
				state_next = edg;
		edg:
			begin
				tick = 1'b1;
				if (level)
					state_next = one;
				else
					state_next = zero;
			end
		one:
			if (!level)
				state_next = zero;
		default:
			state_next = zero;	
	endcase
end

endmodule
